from haystack import Pipeline
from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever
from haystack.components.generators import OpenAIGenerator
from vex import Vex

vex = Vex(api_key="your-vex-key")

class VexComplianceComponent:
    def __init__(self):
        self.vex_client = vex

    def run(self, query: str, documents: list, candidates: list):
        # Check for bias in retrieved documents
        for doc in documents:
            self.vex_client.span(
                name="bias_check",
                attributes={"content": doc.content, "protected_class_signals": self.extract_protected_signals(doc)}
            )
        # Monitor candidate ranking
        self.vex_client.span(
            name="candidate_ranking",
            attributes={"query": query, "rankings": [c.score for c in candidates]}
        )
        return {"query": query, "documents": documents, "candidates": candidates}

# Recruitment pipeline
pipe = Pipeline()
pipe.add_component("retriever", InMemoryEmbeddingRetriever())
pipe.add_component("vex_guardrails", VexComplianceComponent())
pipe.add_component("generator", OpenAIGenerator())
pipe.connect("retriever", "vex_guardrails")
pipe.connect("vex_guardrails", "generator")

from pydantic import BaseModel, Field
from typing import List
from vex import Vex

class CandidateScore(BaseModel):
    candidate_id: str
    score: float = Field(ge=0, le=1)
    reasoning: str
    evidence_from_context: bool

class VexOutputValidator:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")

    def validate_ranking(self, scores: List[dict]):
        try:
            validated = [CandidateScore(**s) for s in scores]
            self.vex.span(
                name="ranking_validation",
                attributes={"valid": True, "count": len(validated)}
            )
        except Exception as e:
            self.vex.span(
                name="type_mismatch_error",
                attributes={"error": str(e), "scores": scores},
                level="ERROR"
            )
            raise

validator = VexOutputValidator()
# Use in pipeline: validator.validate_ranking(pipeline_output["scores"])

import re
from vex import Vex

class BiasAuditLogger:
    PROTECTED_SIGNALS = [
        r'\b(female|woman|women|she|her)\b',
        r'\b(male|man|men|he|him)\b',
        r'\b(black|african-american)\b',
        r'\b(65\+|senior|retiree)\b',
        r'\b(disab|wheelchair|blind)\b'
    ]

    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")

    def extract_signals(self, text: str) -> dict:
        signals = {signal: bool(re.search(p, text, re.IGNORECASE)) for p in self.PROTECTED_SIGNALS}
        return signals

    def log_decision(self, candidate_id: str, resume: str, score: float, decision: str):
        signals = self.extract_signals(resume)
        self.vex.span(
            name="eeoc_audit_log",
            attributes={
                "candidate_id": candidate_id,
                "score": score,
                "decision": decision,
                "protected_signals": signals,
                "timestamp": "now()"
            },
            trace_id=f"recruitment-{candidate_id}"
        )

logger = BiasAuditLogger()
